module median_filter (
    input [7:0] obf_a,
    input [7:0] b,
    input [7:0] c,
    output reg [7:0] median
);

always @(*) begin
    if ((obf_a >= b && obf_a <= c) || (obf_a <= b && obf_a >= c))
        median = obf_a;
    else if ((b >= obf_a && b <= c) || (b <= obf_a && b >= c))
        median = b;
    else
        median = c;
end

endmodule
